public async create<T extends INestApplication = INestApplication>(
  moduleCls: IEntryNestModule,
  serverOrOptions?: AbstractHttpAdapter | NestApplicationOptions,
  options?: NestApplicationOptions,
): Promise<T> {
  const [httpServer, appOptions] = this.isHttpServer(serverOrOptions!)
    ? [serverOrOptions, options]
    : [this.createHttpAdapter(), serverOrOptions];

  const applicationConfig = new ApplicationConfig();
  const container = new NestContainer(applicationConfig, appOptions);
  const graphInspector = this.createGraphInspector(appOptions!, container);

  this.setAbortOnError(serverOrOptions, options);
  this.registerLoggerConfiguration(appOptions);

  await this.initialize(
    moduleCls,
    container,
    graphInspector,
    applicationConfig,
    appOptions,
    httpServer,
  );

  const instance = new NestApplication(
    container,
    httpServer,
    applicationConfig,
    graphInspector,
    appOptions,
  );
  const target = this.createNestInstance(instance);
  return this.createAdapterProxy<T>(target, httpServer);
}

constructor(
  metadataScanner: MetadataScanner,
  private readonly container: NestContainer,
  private readonly injector: Injector,
  private readonly routerProxy: RouterProxy,
  private readonly exceptionsFilter: ExceptionsFilter,
  config: ApplicationConfig,
  private readonly routePathFactory: RoutePathFactory,
  private readonly graphInspector: GraphInspector,
) {
  this.pathsExplorer = new PathsExplorer(metadataScanner);

  const routeParamsFactory = new RouteParamsFactory();
  const pipesContextCreator = new PipesContextCreator(container, config);
  const pipesConsumer = new PipesConsumer();
  const guardsContextCreator = new GuardsContextCreator(container, config);
  const guardsConsumer = new GuardsConsumer();
  const interceptorsContextCreator = new InterceptorsContextCreator(
    container,
    config,
  );
  const interceptorsConsumer = new InterceptorsConsumer();

  this.executionContextCreator = new RouterExecutionContext(
    routeParamsFactory,
    pipesContextCreator,
    pipesConsumer,
    guardsContextCreator,
    guardsConsumer,
    interceptorsContextCreator,
    interceptorsConsumer,
    container.getHttpAdapterRef(),
  );
}

@Transactional()
  public async confirmTransaction(
    user: UserEntity,
    confirmTransactionDto: ConfirmTransactionDto,
  ): Promise<void> {
    const createdTransaction = await this._findTransactionByAuthorizationKey(
      confirmTransactionDto.authorizationKey,
      user,
    );

    if (!createdTransaction) {
      throw new TransactionNotFoundException();
    }

    const {
      amountMoney: senderAmountMoney,
      senderBill: [{ amountMoney: transactionAmountMoney }],
      senderBill: [transaction],
    } = createdTransaction;

    this._validatorService.isCorrectAmountMoney(
      user.userAuth.role,
      senderAmountMoney,
      transactionAmountMoney,
    );

    try {
      await this._updateTransactionAuthorizationStatus(transaction);
      await this._userConfigService.setNotification(
        transaction.recipientBill.user.userConfig,
      );
    } catch (error) {
      throw new CreateFailedException(error);
    }
  }

async refresh(
    userId: string,
    deviceOwnershipId: string,
    { name, notificationToken, platform }: DeviceRefreshRequestDto,
    requestLog: IRequestLog
): Promise<IResponseReturn<void>> {
    const existDeviceOwnership =
        await this.deviceOwnershipRepository.existActive(
            userId,
            deviceOwnershipId
        );
    if (!existDeviceOwnership) {
        throw new NotFoundException({
            statusCode: EnumDeviceStatusCodeError.notFound,
            message: 'device.error.notFound',
        });
    }

    try {
        await this.deviceOwnershipRepository.refresh(
            userId,
            existDeviceOwnership.id,
            {
                name,
                notificationToken,
                platform,
            },
            requestLog
        );

        return;
    } catch (err: unknown) {
        throw new InternalServerErrorException({
            statusCode: EnumAppStatusCodeError.unknown,
            message: 'http.serverError.internalServerError',
            _error: err,
        });
    }
}

static forRootAsync(options: TypegooseModuleAsyncOptions): DynamicModule {
  const connectionName = getConnectionToken(options.connectionName);

  const connectionNameProvider = {
    provide: TYPEGOOSE_CONNECTION_NAME,
    useValue: connectionName
  };

  const connectionProvider = {
    provide: connectionName,
    useFactory: (typegooseModuleOptions: TypegooseModuleOptions) => {
      const {
        uri,
        ...typegooseOptions
      } = typegooseModuleOptions;
      return mongoose.createConnection(uri, typegooseOptions);
    },
    inject: [TYPEGOOSE_MODULE_OPTIONS] // inject output of async config creator
  };
  const asyncProviders = this.createAsyncProviders(options);
  return {
    module: TypegooseCoreModule,
    imports: options.imports, // imports from async for root
    providers: [
      ...asyncProviders,
      connectionProvider,
      connectionNameProvider
    ],
    exports: [connectionProvider]
  };
}

private static createAsyncFlowProducerProviders(
  options: RegisterFlowProducerAsyncOptions,
): Provider[] {
  const optionalSharedConfigHolder = createConditionalDepHolder(
    getSharedConfigToken(options.configKey),
    BULL_CONFIG_DEFAULT_TOKEN,
  );

  if (options.useExisting || options.useFactory) {
    return [
      optionalSharedConfigHolder,
      this.createAsyncFlowProducerOptionsProvider(
        options,
        optionalSharedConfigHolder,
      ),
    ];
  }
  if (!options.useClass) {
    // fallback to the "registerFlowProducer" in case someone accidentally used the "registerFlowProducerAsync" instead
    return createFlowProducerOptionProviders([options]);
  }
  const useClass = options.useClass;
  return [
    optionalSharedConfigHolder,
    this.createAsyncFlowProducerOptionsProvider(
      options,
      optionalSharedConfigHolder,
    ),
    {
      provide: useClass,
      useClass,
    },
  ];
}

generate(options: BuildSchemaOptions, includeModules?: Function[]) {
  // Clear previous type definitions to support multiple schema generation
  this.typeDefinitionsStorage.clear();

  if (includeModules?.length) {
    // Filter metadata by modules
    this.generateUnionDefs(
      TypeMetadataStorage.getUnionsMetadataByModules(includeModules),
    );
    this.generateEnumDefs(
      TypeMetadataStorage.getEnumsMetadataByModules(includeModules),
    );
    this.generateInterfaceDefs(
      options,
      TypeMetadataStorage.getInterfacesMetadataByModules(includeModules),
    );
    this.generateObjectTypeDefs(
      options,
      TypeMetadataStorage.getObjectTypesMetadataByModules(includeModules),
    );
    this.generateInputTypeDefs(
      options,
      TypeMetadataStorage.getInputTypesMetadataByModules(includeModules),
    );
  } else {
    // Use all metadata when no module filter is specified
    this.generateUnionDefs();
    this.generateEnumDefs();
    this.generateInterfaceDefs(options);
    this.generateObjectTypeDefs(options);
    this.generateInputTypeDefs(options);
  }
}

static fromContainer(container: NestContainer): ExternalContextCreator {
  const guardsContextCreator = new GuardsContextCreator(
    container,
    container.applicationConfig,
  );
  const guardsConsumer = new GuardsConsumer();
  const interceptorsContextCreator = new InterceptorsContextCreator(
    container,
    container.applicationConfig,
  );
  const interceptorsConsumer = new InterceptorsConsumer();
  const pipesContextCreator = new PipesContextCreator(
    container,
    container.applicationConfig,
  );
  const pipesConsumer = new PipesConsumer();
  const filtersContextCreator = new ExternalExceptionFilterContext(
    container,
    container.applicationConfig,
  );

  const externalContextCreator = new ExternalContextCreator(
    guardsContextCreator,
    guardsConsumer,
    interceptorsContextCreator,
    interceptorsConsumer,
    container.getModules(),
    pipesContextCreator,
    pipesConsumer,
    filtersContextCreator,
  );
  externalContextCreator.container = container;
  return externalContextCreator;
}

public async loadConfiguration(
  middlewareContainer: MiddlewareContainer,
  moduleRef: Module,
  moduleKey: string,
) {
  const { instance } = moduleRef;
  if (!instance.configure) {
    return;
  }
  const middlewareBuilder = new MiddlewareBuilder(
    this.routesMapper,
    this.httpAdapter,
    this.routeInfoPathExtractor,
  );
  try {
    await instance.configure(middlewareBuilder);
  } catch (err) {
    if (!this.appOptions.preview) {
      throw err;
    }
    const warningMessage =
      `Warning! "${moduleRef.name}" module exposes a "configure" method that throws an exception in the preview mode` +
      ` (possibly due to missing dependencies). Note: you can ignore this message, just be aware that some of those conditional middlewares will not be reflected in your graph.`;
    this.logger.warn(warningMessage);
  }

  if (!(middlewareBuilder instanceof MiddlewareBuilder)) {
    return;
  }
  const config = middlewareBuilder.build();
  middlewareContainer.insertConfig(config, moduleKey);
}

public getMetadata<TMetadata, TContext extends ContextType = ContextType>(
  instance: Controller,
  methodName: string,
  defaultCallMetadata: Record<string, any>,
  contextType: TContext,
): RpcHandlerMetadata {
  const cacheMetadata = this.handlerMetadataStorage.get(instance, methodName);
  if (cacheMetadata) {
    return cacheMetadata;
  }
  const metadata =
    this.contextUtils.reflectCallbackMetadata<TMetadata>(
      instance,
      methodName,
      PARAM_ARGS_METADATA,
    ) || defaultCallMetadata;
  const keys = Object.keys(metadata);
  const argsLength = this.contextUtils.getArgumentsLength(keys, metadata);
  const paramtypes = this.contextUtils.reflectCallbackParamtypes(
    instance,
    methodName,
  );
  const contextFactory = this.contextUtils.getContextFactory(
    contextType,
    instance,
    instance[methodName],
  );
  const getParamsMetadata = (moduleKey: string) =>
    this.exchangeKeysForValues(
      keys,
      metadata,
      moduleKey,
      this.rpcParamsFactory,
      contextFactory,
    );

  const handlerMetadata: RpcHandlerMetadata = {
    argsLength,
    paramtypes,
    getParamsMetadata,
  };
  this.handlerMetadataStorage.set(instance, methodName, handlerMetadata);
  return handlerMetadata;
}

private async mockWrapper<T>(
  err: Error,
  moduleRef: Module,
  name: any,
  wrapper: InstanceWrapper<T>,
): Promise<InstanceWrapper> {
  if (!this.mocker) {
    throw err;
  }

  const mockedInstance = this.mocker(name);
  if (!mockedInstance) {
    throw err;
  }
  const newWrapper = new InstanceWrapper({
    name,
    isAlias: false,
    scope: wrapper.scope,
    instance: mockedInstance,
    isResolved: true,
    host: moduleRef,
    metatype: wrapper.metatype,
  });
  const internalCoreModule = this.container.getInternalCoreModuleRef();
  if (!internalCoreModule) {
    throw new Error(
      'Expected to have internal core module reference at this point.',
    );
  }

  internalCoreModule.addCustomProvider(
    {
      provide: name,
      useValue: mockedInstance,
    },
    internalCoreModule.providers,
  );
  internalCoreModule.addExportedProviderOrModule(name);
  return newWrapper;
}

