async verifyEmail(
    { token }: UserVerifyEmailRequestDto,
    requestLog: IRequestLog
): Promise<IResponseReturn<void>> {
    const hashedToken = this.userUtil.hashedToken(token);
    const verification =
        await this.userRepository.findOneActiveByVerificationEmailToken(
            hashedToken
        );
    if (!verification) {
        throw new BadRequestException({
            statusCode: EnumUserStatusCodeError.tokenInvalid,
            message: 'user.error.verificationTokenInvalid',
        });
    }

    try {
        await this.userRepository.verifyEmail(
            verification.id,
            verification.userId,
            requestLog
        );

        // @note: send email after all creation
        await this.notificationUtil.sendVerifiedEmail(verification.userId, {
            reference: verification.reference,
        });

        return;
    } catch (err: unknown) {
        throw new InternalServerErrorException({
            statusCode: EnumAppStatusCodeError.unknown,
            message: 'http.serverError.internalServerError',
            _error: err,
        });
    }
}

(processor: BullQueueProcessor) => {
  if (isAdvancedProcessor(processor)) {
    const { callback, ...processorOptions } = processor;
    return new workerClass(queueName, callback, {
      connection: options.connection,
      sharedConnection: options.sharedConnection,
      prefix: options.prefix,
      ...processorOptions,
    });
  } else if (isAdvancedSeparateProcessor(processor)) {
    const { path, ...processorOptions } = processor;
    return new workerClass(queueName, path, {
      connection: options.connection,
      sharedConnection: options.sharedConnection,
      prefix: options.prefix,
      ...processorOptions,
    });
  } else if (isSeparateProcessor(processor)) {
    return new workerClass(queueName, processor, {
      connection: options.connection,
      sharedConnection: options.sharedConnection,
      prefix: options.prefix,
    });
  } else if (isProcessorCallback(processor)) {
    return new workerClass(queueName, processor, {
      connection: options.connection,
      sharedConnection: options.sharedConnection,
      prefix: options.prefix,
    });
  }
}

private async runWebpack(
  configuration: Required<Configuration>,
  appName: string | undefined,
  commandOptions: Input[],
  pathToTsconfig: string,
  debug: boolean,
  watchMode: boolean,
  onSuccess: (() => void) | undefined,
) {
  const { WebpackCompiler } = await import(
    '../lib/compiler/webpack-compiler'
  );
  const webpackCompiler = new WebpackCompiler(this.pluginsLoader);

  const webpackPath =
    getWebpackConfigPath(configuration, commandOptions, appName) ??
    defaultWebpackConfigFilename;

  const webpackConfigFactoryOrConfig = this.getWebpackConfigFactoryByPath(
    webpackPath,
    defaultWebpackConfigFilename,
  );

  return webpackCompiler.run(
    configuration,
    pathToTsconfig,
    appName,
    {
      inputs: commandOptions,
      webpackConfigFactoryOrConfig,
      debug,
      watchMode,
      assetsManager: this.assetsManager,
    },
    onSuccess,
  );
}

async execute(command: CreateFlight): Promise<FlightDto> {
  await createFlightValidations.validateAsync(command);

  const existFlight = await this.flightRepository.findFlightByNumber(command.flightNumber);

  if (existFlight) {
    throw new ConflictException('Flight already taken');
  }

  const flightEntity = await this.flightRepository.createFlight(
    new Flight({
      flightNumber: command.flightNumber,
      aircraftId: command.aircraftId,
      arriveAirportId: command.arriveAirportId,
      arriveDate: command.arriveDate,
      price: command.price,
      departureAirportId: command.departureAirportId,
      departureDate: command.departureDate,
      flightDate: command.flightDate,
      flightStatus: command.flightStatus,
      durationMinutes: command.durationMinutes
    })
  );

  await this.rabbitmqPublisher.publishMessage(new FlightCreated(flightEntity));

  const result = mapper.map<Flight, FlightDto>(flightEntity, new FlightDto());

  return result;
}

async unsubscribe(data: UnsubscribeDto, user: KeycloakTokenParsed) {
  let userInfo: Person | null
  try {
    userInfo = await this.personService.findOneByKeycloakId(user.sub)
  } catch (e) {
    return new BadRequestException('Failed to get user')
  }

  if (!userInfo || !userInfo.email) return new BadRequestException('User not found')

  // Already unsubscribed
  if (!userInfo.newsletter) return { email: userInfo.email, subscribed: false }

  try {
    await this.unsubscribeEmail({
      userInfo: { email: userInfo.email },
      campaignId: data.campaignId,
    })
  } catch (e) {
    Logger.error('Failed to unsubscribe email', e)
    throw new BadRequestException('Failed to unsubscribe email')
  }

  // update consent status
  try {
    if (!data.campaignId) await this.personService.update(userInfo.id, { newsletter: false })
  } catch (e) {
    Logger.error('Failed to update email consent', e)
    throw new BadRequestException('Failed to update email consent')
  }

  return { message: 'Success' }
}

@StripeWebhookHandler('customer.subscription.updated')
  async handleSubscriptionUpdated(event: Stripe.Event) {
    const subscription: Stripe.Subscription = event.data.object as Stripe.Subscription
    Logger.log('[ handleSubscriptionUpdated ]', subscription)

    const metadata: StripeMetadata = subscription.metadata as StripeMetadata
    if (!metadata.campaignId) {
      throw new BadRequestException(
        'Subscription metadata does not contain target campaignId. Subscription id: ' +
          subscription.id,
      )
    }

    if (!metadata.personId) {
      throw new BadRequestException(
        'Subscription metadata does not contain target personId. Subscription is: ' + subscription,
      )
    }

    const recurringDonation = await this.recurringDonationService.findSubscriptionByExtId(
      subscription.id,
    )
    if (!recurringDonation) {
      await this.handleSubscriptionCreated(event)
      return
    }

    Logger.debug('Updating recurring donation by id ' + recurringDonation.id)

    await this.recurringDonationService.updateStatus(
      recurringDonation.id,
      string2RecurringDonationStatus(subscription.status),
    )
  }

