async execute(
  request: UpdateNotificationStatusRequest,
): Promise<Result<void, UseCaseError>> {
  const { notificationId, status, reason } = request;

  const findResult =
    await this.notificationRepository.findById(notificationId);
  if (findResult.isFailure) return findResult;

  const notification = findResult.value;
  if (!notification) {
    return ErrorFactory.UseCaseError(
      `Notification ${notificationId} not found`,
    );
  }

  switch (status) {
    case NotificationStatus.DELIVERED:
      notification.markAsDelivered();
      break;
    case NotificationStatus.READ:
      notification.markAsRead();
      break;
    case NotificationStatus.FAILED:
      notification.markAsFailed(reason || 'Unknown error');
      break;
  }

  const saveResult = await this.notificationRepository.save(notification);
  if (saveResult.isFailure) return saveResult;

  return Result.success(undefined);
}

async discover(input: ServiceInput): Promise<ServiceResult> {
  // 1. Check if url is already processed
  if (
    await this.contentRepository.exists(this.generateContentName(input.url))
  ) {
    throw new ContentAlreadyDiscoveredException(input.url);
  }

  // 2. Get or Create Crawl Metadata
  const metadata = await this.getOrCreateCrawlMetadata(input);

  // 3. Resolve DNS
  const dnsResult = await this.dnsResolver.resolveDns(
    new URL(input.url).hostname,
  );

  // 4. Download content
  const downloadResult = await this.contentDownloader.download({
    url: input.url,
    ip: dnsResult.ip,
  });

  // 5. Save content
  const contentName = this.generateContentName(input.url);
  await this.contentRepository.create({
    name: contentName,
    body: downloadResult.content,
    type: downloadResult.contentType,
  });

  // 6. Process content
  if (input.currentDepth > 0) {
    await this.contentProcessorQueueProducer.send({
      contentName,
      aux: {
        depth: input.currentDepth,
        crawlId: metadata.id,
      },
    });
  }

  return {
    url: input.url,
    resolvedIp: dnsResult.ip,
    resolverServer: dnsResult.resolverServer,
    contentName,
    contentType: downloadResult.contentType,
  };
}

protected transformPrimitive(value: any, metadata: ArgumentMetadata) {
  if (!metadata.data) {
    // leave top-level query/param objects unmodified
    return value;
  }
  const { type, metatype } = metadata;
  if (type !== 'param' && type !== 'query') {
    return value;
  }
  if (metatype === Boolean) {
    if (isUndefined(value)) {
      // This is an workaround to deal with optional boolean values since
      // optional booleans shouldn't be parsed to a valid boolean when
      // they were not defined
      return undefined;
    }
    // Any fasly value but `undefined` will be parsed to `false`
    return value === true || value === 'true';
  }
  if (metatype === Number) {
    if (isUndefined(value)) {
      // This is a workaround to deal with optional numeric values since
      // optional numerics shouldn't be parsed to a valid number when
      // they were not defined
      return undefined;
    }
    return +value;
  }
  if (metatype === String && !isUndefined(value)) {
    return String(value);
  }
  return value;
}

createTypePropertyAssignment(
  factory: ts.NodeFactory,
  node: ts.MethodDeclaration,
  typeChecker: ts.TypeChecker,
  existingProperties: ts.NodeArray<ts.PropertyAssignment>,
  hostFilename: string,
  options: PluginOptions
) {
  if (hasPropertyKey('type', existingProperties)) {
    return undefined;
  }
  const signature = typeChecker.getSignatureFromDeclaration(node);
  const type = typeChecker.getReturnTypeOfSignature(signature);
  if (!type) {
    return undefined;
  }
  const typeReferenceDescriptor = getTypeReferenceAsString(type, typeChecker);
  if (!typeReferenceDescriptor.typeName) {
    return undefined;
  }
  if (typeReferenceDescriptor.typeName.includes('node_modules')) {
    return undefined;
  }
  const identifier = typeReferenceToIdentifier(
    typeReferenceDescriptor,
    hostFilename,
    options,
    factory,
    type,
    this._typeImports
  );
  return factory.createPropertyAssignment('type', identifier);
}

async transform(
    value: {
        cursor?: string;
        perPage?: number | string;
    } & IPaginationQueryCursorParams
): Promise<IPaginationQueryCursorParams> {
    try {
        const finalPerPage = this.validatePerPage(value.perPage);
        const trimmedCursor = this.validateAndSanitizeCursor(
            value.cursor
        );

        this.addToRequestInstance(finalPerPage, trimmedCursor);

        return {
            ...value,
            limit: finalPerPage,
            cursor: trimmedCursor,
            cursorField: defaultCursorField,
        };
    } catch (error) {
        if (error instanceof UnprocessableEntityException) {
            throw error;
        }

        throw new UnprocessableEntityException({
            statusCode: EnumPaginationStatusCodeError.invalidCursorPaginationParams,
            message: 'pagination.error.invalidCursorPaginationParams',
        });
    }
}

transform(
    value: {
        page?: number | string;
        perPage?: number | string;
    } & IPaginationQueryOffsetParams
): IPaginationQueryOffsetParams {
    try {
        const finalPage = this.validateAndParsePage(value.page);
        const finalPerPage = this.validateAndParsePerPage(
            value.perPage
        );

        const skip = (finalPage - 1) * finalPerPage;
        this.addToRequestInstance(finalPage, finalPerPage);

        return {
            ...value,
            limit: finalPerPage,
            skip: skip,
        };
    } catch (error) {
        if (error instanceof UnprocessableEntityException) {
            throw error;
        }

        throw new UnprocessableEntityException({
            statusCode:
                EnumPaginationStatusCodeError.invalidOffsetPaginationParams,
            message: 'pagination.error.invalidOffsetPaginationParams',
        });
    }
}

async registerUserByGithubToken(
  dto: ThirdLoginDto,
  ip: string,
  userAgent: string,
) {

  let result = null
  const { type, username, avatar, address, from, uniqueId, nickName, password } = dto
  switch (type) {
    case 'github':
      try {

        // 校验三方用户是否存在
        await this.userService.checkThirdUserExist(type, uniqueId)
        // 校验用户名和邮箱是否已经存在
        await this.userService.checkUserExist(username);

        const user: UserCreateDto = {
          username,
          avatar,
          password: '',
          from,
          uniqueId,
          address,
          nickName
        };
        user.password = await argon2.hash(password);

        await this.userService.create(user, false);

        const newUser = await this.userService.findUserInfoByUsername(username);

        result = await this.authService.loginDetails(newUser.id, ip, userAgent);
      } catch (error) {
        console.log(error);
        throw new BusinessException(ErrorEnum.AUTH_CANNOT_LOGIN);
      }
      break
  }

  return result;
}

assignee => {
  if (!assignment[assignee]) {
    assignment[assignee] = {};
  }

  // add topics to each member
  group.topics.forEach(topic => {
    if (!assignment[assignee][topic]) {
      assignment[assignee][topic] = [];
    }

    // see if the topic and partition belong to a previous assignment
    if (
      previousAssignment[assignee] &&
      !isUndefined(previousAssignment[assignee][topic])
    ) {
      // take the minimum partition since replies will be sent to the minimum partition
      const firstPartition = previousAssignment[assignee][topic];

      // create the assignment with the first partition
      assignment[assignee][topic].push(firstPartition);

      // find and remove this topic and partition from the topicPartitions to be assigned later
      const topicsPartitionsIndex = topicsPartitions.findIndex(
        topicPartition => {
          return (
            topicPartition.topic === topic &&
            topicPartition.partitionId === firstPartition
          );
        },
      );

      // only continue if we found a partition matching this topic
      if (topicsPartitionsIndex !== -1) {
        // remove inline
        topicsPartitions.splice(topicsPartitionsIndex, 1);
      }
    }
  });
}

